from __future__ import annotations


def request_size_limit_plugin(allowed_payload_size_mb: int, *, route_name: str | None = None) -> dict[str, object]:
    if allowed_payload_size_mb <= 0:
        raise ValueError("allowed payload size must be positive")

    plugin: dict[str, object] = {
        "name": "request-size-limiting",
        "config": {"allowed_payload_size": allowed_payload_size_mb},
    }
    if route_name:
        plugin["route"] = {"name": route_name}
    return plugin

import unittest

from kong_deck_gateway.policy import request_size_limit_plugin


class GatewayPolicyTests(unittest.TestCase):
    def test_request_size_limit_plugin_uses_kong_plugin_name(self):
        plugin = request_size_limit_plugin(10, route_name="uploads")

        self.assertEqual(plugin["name"], "request-size-limiting")
        self.assertEqual(plugin["config"]["allowed_payload_size"], 10)
        self.assertEqual(plugin["route"]["name"], "uploads")

    def test_request_size_limit_must_be_positive(self):
        with self.assertRaises(ValueError):
            request_size_limit_plugin(0)


if __name__ == "__main__":
    unittest.main()

from __future__ import annotations

PUBLIC_BIND_ADDRESSES = {"0.0.0.0", "::"}


def admin_api_is_private(bind_address: str, *, trusted_networks: list[str] | tuple[str, ...] = ()) -> bool:
    if bind_address in PUBLIC_BIND_ADDRESSES and not trusted_networks:
        return False
    return bind_address in {"127.0.0.1", "localhost"} or bool(trusted_networks)


def admin_api_security_warnings(bind_address: str, *, trusted_networks: list[str] | tuple[str, ...] = ()) -> tuple[str, ...]:
    warnings: list[str] = []
    if bind_address in PUBLIC_BIND_ADDRESSES:
        warnings.append("admin_api_public_bind")
    if not trusted_networks and bind_address not in {"127.0.0.1", "localhost"}:
        warnings.append("trusted_network_missing")
    return tuple(warnings)

import unittest

from kong_deck_gateway.admin_security import admin_api_is_private, admin_api_security_warnings


class AdminSecurityTests(unittest.TestCase):
    def test_localhost_admin_api_is_private(self):
        self.assertTrue(admin_api_is_private("127.0.0.1"))

    def test_public_bind_without_trusted_network_warns(self):
        warnings = admin_api_security_warnings("0.0.0.0")

        self.assertIn("admin_api_public_bind", warnings)
        self.assertIn("trusted_network_missing", warnings)
        self.assertFalse(admin_api_is_private("0.0.0.0"))


